import{_ as n,j as t,o as h,v as i}from"./chunks/framework.OlxNbC8G.js";const e=JSON.parse('{"title":"Event là gì ?","description":"","frontmatter":{"footer":true,"title":"Event là gì ?","authors":["lethanh"],"date":"2024-04-015","outline":"deep","draft":true,"group":"2. Message and event stream"},"headers":[{"level":1,"title":"Event là gì ?","slug":"event-la-gi","link":"#event-la-gi","children":[{"level":2,"title":"Event là gì ?","slug":"event-la-gi-1","link":"#event-la-gi-1","children":[{"level":3,"title":"Đặc điểm của event.","slug":"đac-điem-cua-event","link":"#đac-điem-cua-event","children":[]},{"level":3,"title":"Vai trò của Event trong hệ thống:","slug":"vai-tro-cua-event-trong-he-thong","link":"#vai-tro-cua-event-trong-he-thong","children":[]},{"level":3,"title":"Ví dụ","slug":"vi-du","link":"#vi-du","children":[{"level":4,"title":"Ví dụ 1","slug":"vi-du-1","link":"#vi-du-1","children":[{"level":5,"title":"Ví dụ về hệ thống đặt hàng.","slug":"vi-du-ve-he-thong-đat-hang","link":"#vi-du-ve-he-thong-đat-hang","children":[{"level":6,"title":"Bối cảnh:","slug":"boi-canh","link":"#boi-canh","children":[]},{"level":6,"title":"Quá trình sự lý event","slug":"qua-trinh-su-ly-event","link":"#qua-trinh-su-ly-event","children":[]}]}]}]}]}]}],"relativePath":"study/thanhlv-study-2024/2024-04-16-event-la-gi.md","filePath":"study/thanhlv-study-2024/2024-04-16-event-la-gi.md","lastUpdated":1713350151000}'),g={name:"study/thanhlv-study-2024/2024-04-16-event-la-gi.md"},a=[i('<h1 id="event-la-gi" tabindex="-1">Event là gì ? <a class="header-anchor" href="#event-la-gi" aria-label="Permalink to &quot;Event là gì ?&quot;">​</a></h1><p>Sau khi đã hiểu về <strong><a href="./2024-04-15-message-la-gi.html">Message</a></strong>, bước tiếp theo không kém phần quan trọng là khám phá về <strong>Event</strong>.</p><p><strong>Event</strong> là một khái niệm cốt lõi trong việc xây dựng các hệ thống và tương tác. Không giống như Message chủ yếu mang thông tin, Event đại diện cho một sự kiện, một thay đổi trạng thái hoặc một hành động nào đó đã xảy ra trong hệ thống.</p><p>Event không chỉ là thông báo về một sự kiện đã xảy ra; nó còn là tín hiệu để kích hoạt các hành động tiếp theo, làm cho hệ thống trở nên linh hoạt và phản ứng nhanh chóng với các thay đổi. Điều này tạo nên một hệ thống có khả năng tự điều chỉnh, tự phục hồi và tối ưu hóa dựa trên các sự kiện xảy ra.</p><p>Hãy cùng mình đi sâu vào việc tìm hiểu về bản chất của Event, cách chúng được tạo ra, phát tán, và xử lý trong các hệ thống. Chúng ta sẽ khám phá cách Event tạo ra một môi trường động, nơi mà các thành phần có thể tương tác một cách linh hoạt và hiệu quả.</p><p>Bắt đầu cuộc hành trình khám phá về Event, chúng ta sẽ mở ra những hiểu biết mới và cách tiếp cận mới trong việc xây dựng và thiết kế hệ thống. Hãy cùng nhau tiếp tục hành trình này và khám phá sức mạnh của Event trong việc tạo ra các hệ thống thông minh và tự động!</p><nav class="table-of-contents"><ul><li><a href="#event-la-gi-1">Event là gì ?</a><ul><li><a href="#đac-điem-cua-event">Đặc điểm của event.</a></li><li><a href="#vai-tro-cua-event-trong-he-thong">Vai trò của Event trong hệ thống:</a></li><li><a href="#vi-du">Ví dụ</a><ul><li><a href="#vi-du-1">Ví dụ 1</a><ul><li><a href="#vi-du-ve-he-thong-đat-hang">Ví dụ về hệ thống đặt hàng.</a><ul><li><a href="#boi-canh">Bối cảnh:</a></li><li><a href="#qua-trinh-su-ly-event">Quá trình sự lý event</a></li></ul></li></ul></li></ul></li></ul></li></ul></nav><h2 id="event-la-gi-1" tabindex="-1">Event là gì ? <a class="header-anchor" href="#event-la-gi-1" aria-label="Permalink to &quot;Event là gì ?&quot;">​</a></h2><ul><li><p>Event có thể được hiểu là một sự kiện, một thay đổi trạng thái, hoặc một hành động cụ thể nào đó xảy ra trong hệ thống hoặc ứng dụng.</p></li><li><p>Thông thường <strong>Event</strong> sẽ được tạo sau khi một <strong>Message</strong> kết thúc (Thành công hoặc thất bại), tùy nhiên điều đó không bắt buộc. (Có thể từ một Event khác, từ kết quả của một tính toán định kỳ(Định kỳ 10s đo thân nhiệt).....)</p></li></ul><h3 id="đac-điem-cua-event" tabindex="-1">Đặc điểm của event. <a class="header-anchor" href="#đac-điem-cua-event" aria-label="Permalink to &quot;Đặc điểm của event.&quot;">​</a></h3><ul><li><p><strong>Thời điểm xác định</strong>: Mỗi Event đều liên quan đến một thời điểm cụ thể Event đó xảy ra.(Ví dụ 12h)</p></li><li><p><strong>Thông tin</strong>: Event mang theo thông tin liên quan đến event đó, giúp các thành phần khác trong hệ thống có thể phản ứng một cách thích hợp.</p></li><li><p><strong>Không đồng bộ</strong>: Việc xử lý Event <strong>thường</strong> diễn ra không đồng bộ, tức là hệ thống không cần dừng lại để chờ đợi 1 event xử lý thành công.</p></li><li><p><strong>Kích hoạt hành động</strong>: Event có thể có thể được sử dụng để kích hoạt 1 hoặc nhiều hành động, quy trình(job) trong hệ thống tạo điều kiện cho việc phản ứng linh hoạt các thay đổi.</p></li><li><p><strong>Tính phân tán(Broadcast Nature)</strong>: Khác với <a href="./2024-04-15-message-la-gi.html">Message</a> sẽ có người nhận cụ thể vì nó là yêu cầu gửi đến thành phần khác, Event không nhất thiết phải có một người nhận cụ thể.</p><ul><li>Event được phát ra để thông báo một sự kiện thay đổi trạng thái, hành động xảy ra. Ứng dụng tạo ra event và không cần biết ai sẽ nhận event và xử lý nó.</li><li>Các thành phần trong hệ thống có thể lắng nghe tất cả hoặc đăng ký lắng nghe các event mà hệ thống quan tâm sau đó phản ứng với event xảy ra mà không cần Evetn chỉ định trực tiếp người nhận.</li></ul></li></ul><h3 id="vai-tro-cua-event-trong-he-thong" tabindex="-1">Vai trò của Event trong hệ thống: <a class="header-anchor" href="#vai-tro-cua-event-trong-he-thong" aria-label="Permalink to &quot;Vai trò của Event trong hệ thống:&quot;">​</a></h3><ul><li><p><strong>Tăng cường tính linh hoạt</strong>: Event giúp các thành phần trong hệ thống có thể tương tác với nhau một cách linh hoạt và không cần phải biết trước về sau</p></li><li><p><strong>Phản ứng với thay đổi</strong>: Hệ thống có thể được thiết kế để tự động phản ứng với các Event giúp xử lý các thay đổi một cách nhanh chóng và hiệu quả.</p></li><li><p><strong>Tách biệt nghiệp vụ</strong>: Event giúp tách biệt nghiệp vụ và logic xử lý làm cho hệ thống dễ quản lý và bảo trì.</p><ul><li>Các thành phần không phụ thuộc trực tiếp vào nhau để hoàn thành nghiệm vụ, thay vào đó tương tác thông qua nhận và gửi event</li></ul></li><li></li><li><p><strong>Tối ưu hóa hiệu suất</strong>: Việc sử dụng Event có thể giúp tối ưu hóa hiệu suất hệ thống bằng cách giảm thiểu sự phụ thuộc và chờ đợi giữa các thành phần.</p></li></ul><h3 id="vi-du" tabindex="-1">Ví dụ <a class="header-anchor" href="#vi-du" aria-label="Permalink to &quot;Ví dụ&quot;">​</a></h3><h4 id="vi-du-1" tabindex="-1">Ví dụ 1 <a class="header-anchor" href="#vi-du-1" aria-label="Permalink to &quot;Ví dụ 1&quot;">​</a></h4><h5 id="vi-du-ve-he-thong-đat-hang" tabindex="-1">Ví dụ về hệ thống đặt hàng. <a class="header-anchor" href="#vi-du-ve-he-thong-đat-hang" aria-label="Permalink to &quot;Ví dụ về hệ thống đặt hàng.&quot;">​</a></h5><h6 id="boi-canh" tabindex="-1"><strong>Bối cảnh:</strong> <a class="header-anchor" href="#boi-canh" aria-label="Permalink to &quot;**Bối cảnh:**&quot;">​</a></h6><ul><li>Khi một khách hàng hoàn tất quá trình đặt hàng trên web thương mai điện tử, hệ thống sẽ tạo ra một event <strong>&quot;Đặt hàng mới&quot;</strong>. (Ví dụ sẽ là Thanh toán khi nhận hàng)</li></ul><h6 id="qua-trinh-su-ly-event" tabindex="-1">Quá trình sự lý event <a class="header-anchor" href="#qua-trinh-su-ly-event" aria-label="Permalink to &quot;Quá trình sự lý event&quot;">​</a></h6><ul><li><ol><li>Hệ thống phát ra Event <strong>&quot;Đặt hàng mới&quot;</strong>.</li></ol><ul><li>Hệ thống đặt hàng tạo và phát ra event <strong>&quot;Đặt hàng mới&quot;</strong>, bao gồm tất cả thông tin cần thiết về đơn hàng, ID đơn hàng, thông tin sản phẩm, thông tin khách hàng, tổng giá trị đơn.</li></ul></li><li><ol start="2"><li>Xử lý kho hàng:</li></ol><ul><li>Hệ thống quản lý kho hàng sẽ lắng nghẹ event <strong>&quot;Đặt hàng mới&quot;</strong>. Khi nhận được event, nó kiểm tra sự có sẵn của sản phẩm trong kho. Nếu thiếu hàng nó sẽ phát ra Event <strong>&quot;Yêu cầu bổ xung hàng&quot;</strong> để thông báo cho bộ phận bán hàng.</li></ul></li><li><ol start="3"><li>Xử lý thanh toán :</li></ol><ul><li>Hệ thống thanh toán sẽ lắng nghe Event <strong>&quot;Đặt hàng mới&quot;</strong>. Dựa trên thông tin đơn hàng, tiến hành xác minh và xử lý thanh tó từ khách hàng.</li><li>Nếu thanh toán thành công, hệ thống sẽ phát Event <strong>&quot;Thanh toán thành công&quot;</strong>; nếu thất bại hệ thống phát Event <strong>&quot;Thanh toán thất bại&quot;</strong></li></ul></li></ul>',20)];const l=n(g,[["render",function(n,i,e,g,l,c){return h(),t("div",null,a)}]]);export{e as __pageData,l as default};
